const { createClient } = require('@supabase/supabase-js');
const url = '[REDACTED_SUPABASE_URL]';
const key1 = '[REDACTED_SUPABASE_KEY]';
const key2 = '$(grep NEXT_PUBLIC_SUPABASE_ANON_KEY .env.local | cut -d= -f2)';
(async () => {
  for (const [name, key] of [['.env', key1], ['.env.local', key2]]) {
    const sb = createClient(url, key, { auth: { persistSession: false } });
    try {
      const { data, error } = await sb.auth.getSession();
      console.log(name, '->', error ? 'FAIL: ' + error.message : 'OK');
    } catch(e) {
      console.log(name, '->', 'ERROR:', e.message);
    }
  }
})();
